### Async Offset Commit with Retry

```java
public class AsyncCommitWithRetry {
    static class RetryableOffsetCommitCallback implements OffsetCommitCallback {
        private KafkaConsumer<String, String> consumer;
        private int retries;

        RetryableOffsetCommitCallback(KafkaConsumer<String, String> consumer) {
            this.consumer = consumer;
            this.retries = 0;
        }

        @Override
        public void onComplete(Map<TopicPartition, OffsetAndMetadata> offsets,
                              Exception exception) {
            if (exception == null) {
                System.out.println("Commit succeeded for offsets: " + offsets);
                return;
            }

            if (exception instanceof RetriableCommitFailedException && retries < 3) {
                retries++;
                System.out.println("Retriable failure, retrying... (attempt " + retries + ")");
                consumer.commitAsync(offsets, this);  // Retry
            } else {
                System.err.println("Permanent or too many retries: " + exception.getMessage());
                // Log and move on - cannot safely retry
            }
        }
    }

    public static void main(String[] args) {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "my-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false");

        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
        consumer.subscribe(Collections.singleton("orders"));

        try {
            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(1));

                for (ConsumerRecord<String, String> record : records) {
                    System.out.println("Message: " + record.value());
                }

                // Async commit with retry callback
                if (records.count() > 0) {
                    consumer.commitAsync(new RetryableOffsetCommitCallback(consumer));
                }
            }
        } finally {
            // Final sync commit before closing
            consumer.commitSync();
            consumer.close();
        }
    }
}
