```java
public class RobustConsumer {
    public static void main(String[] args) {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "my-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");

        KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
        consumer.subscribe(Collections.singleton("orders"));

        try {
            while (true) {
                try {
                    ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(1));

                    for (ConsumerRecord<String, String> record : records) {
                        try {
                            processOrder(record);
                        } catch (RecordDeserializationException e) {
                            // Bad record - skip it
                            System.err.println("Skipping bad record at " + e.offset());
                            consumer.seek(e.topicPartition(), e.offset() + 1);
                        }
                    }

                    consumer.commitSync();

                } catch (OffsetOutOfRangeException e) {
                    System.err.println("Offset out of range, seeking to end");
                    consumer.seekToEnd(e.partitions());

                } catch (NoOffsetForPartitionException e) {
                    System.err.println("No committed offset, seeking to beginning");
                    consumer.seekToBeginning(e.partitions());

                } catch (WakeupException e) {
                    System.out.println("Shutdown requested");
                    break;

                } catch (KafkaException e) {
                    System.err.println("Kafka error: " + e.getMessage());
                    // Log and continue
                }
            }
        } finally {
            consumer.close();
        }
    }

    static void processOrder(ConsumerRecord<String, String> record) {
        // Simulate processing that may fail
        System.out.println("Processing: " + record.value());
    }
}
